#include <iostream>

long long calculateFactorial(int n);

int main() {
    int num;
    std::cin >> num;
    long long fact = calculateFactorial(num);
    if (fact == -1) {
        std::cout << "Factorial is not defined for negative numbers." << std::endl;
    } else {
        std::cout << "The factorial of " << num << " is: " << fact << std::endl;
    }
    return 0;
}
